import { io } from 'socket.io-client';

class SocketService {
  constructor() {
    this.socket = null;
    this.isConnected = false;
    this.currentRoom = null;
    this.userId = null;
    this.userColor = null;
  }

  connect(serverUrl = 'http://localhost:3001') {
    if (this.socket) {
      this.disconnect();
    }

    this.socket = io(serverUrl, {
      transports: ['websocket', 'polling']
    });

    this.socket.on('connect', () => {
      console.log('✅ Connected to RTC server');
      this.isConnected = true;
    });

    this.socket.on('disconnect', () => {
      console.log('❌ Disconnected from RTC server');
      this.isConnected = false;
    });

    this.socket.on('connect_error', (error) => {
      console.error('❌ Connection error:', error);
    });

    return this.socket;
  }

  disconnect() {
    if (this.socket) {
      this.socket.disconnect();
      this.socket = null;
      this.isConnected = false;
      this.currentRoom = null;
    }
  }

  // Room management
  joinRoom(roomId) {
    if (!this.socket || !this.isConnected) {
      console.error('Socket not connected');
      return;
    }

    this.currentRoom = roomId;
    this.socket.emit('join-room', roomId);
  }

  createRoom() {
    return fetch('http://localhost:3001/api/create-room')
      .then(response => response.json())
      .then(data => data.roomId);
  }

  // Drawing events
  emitLineAdd(line) {
    if (this.socket && this.currentRoom) {
      this.socket.emit('line-add', line);
    }
  }

  emitLineUpdate(lineData) {
    if (this.socket && this.currentRoom) {
      this.socket.emit('line-update', lineData);
    }
  }

  emitLineRemove(lineId) {
    if (this.socket && this.currentRoom) {
      this.socket.emit('line-remove', lineId);
    }
  }

  // Shape events
  emitShapeAdd(shape) {
    if (this.socket && this.currentRoom) {
      this.socket.emit('shape-add', shape);
    }
  }

  emitShapeUpdate(shapeData) {
    if (this.socket && this.currentRoom) {
      this.socket.emit('shape-update', shapeData);
    }
  }

  // Cursor events
  emitCursorMove(x, y) {
    if (this.socket && this.currentRoom) {
      this.socket.emit('cursor-move', { x, y });
    }
  }

  // Event listeners
  onRoomState(callback) {
    if (this.socket) {
      this.socket.on('room-state', (data) => {
        this.userId = data.userId;
        this.userColor = data.userColor;
        callback(data);
      });
    }
  }

  onUserJoined(callback) {
    if (this.socket) {
      this.socket.on('user-joined', callback);
    }
  }

  onUserLeft(callback) {
    if (this.socket) {
      this.socket.on('user-left', callback);
    }
  }

  onLineAdd(callback) {
    if (this.socket) {
      this.socket.on('line-add', callback);
    }
  }

  onLineUpdate(callback) {
    if (this.socket) {
      this.socket.on('line-update', callback);
    }
  }

  onLineRemove(callback) {
    if (this.socket) {
      this.socket.on('line-remove', callback);
    }
  }

  onShapeAdd(callback) {
    if (this.socket) {
      this.socket.on('shape-add', callback);
    }
  }

  onShapeUpdate(callback) {
    if (this.socket) {
      this.socket.on('shape-update', callback);
    }
  }

  onCursorMove(callback) {
    if (this.socket) {
      this.socket.on('cursor-move', callback);
    }
  }

  // Cleanup
  removeAllListeners() {
    if (this.socket) {
      this.socket.removeAllListeners();
    }
  }

  // Getters
  getConnectionStatus() {
    return this.isConnected;
  }

  getCurrentRoom() {
    return this.currentRoom;
  }

  getUserInfo() {
    return {
      userId: this.userId,
      userColor: this.userColor
    };
  }
}

// Export singleton instance
const socketService = new SocketService();
export default socketService;
